What is the output of the following code?

data = {"x": 10, "y": 20, "z": 30}
keys = ["y", "a", "x", "z"]
result = 10

for key in keys:
    try:
        if key == "x":
            result = result - data[key] * 2
            break
        elif key == "z":
            result = result + data[key] 
        else:
            result = result - data[key] 
    except KeyError:
        result = result + 10

print(result)

